INSERT INTO questions (section, type, content, correct_answer, cefr_level, difficulty, competency_tag, aircraft_context, role_tag, active, is_latest, version_number) VALUES
-- Grammar (20)
('grammar','multiple_choice','The technician _____ the landing gear before the aircraft departed.\nA) inspect\nB) inspected\nC) inspecting\nD) has inspect','B','A2','easy','tense_usage','landing_gear','maintenance',true,true,1),
('grammar','multiple_choice','All maintenance tasks _____ be completed before the aircraft is released.\nA) must\nB) can\nC) might\nD) would','A','B1','easy','structural_accuracy','general','maintenance',true,true,1),
('grammar','multiple_choice','The engine oil _____ changed every 500 flight hours.\nA) is\nB) are\nC) were\nD) been','A','A2','easy','passive_voice','engine','maintenance',true,true,1),
('grammar','multiple_choice','If the hydraulic pressure _____ too low, the warning light will illuminate.\nA) is\nB) will be\nC) was\nD) has been','A','B1','medium','conditional_forms','hydraulic','maintenance',true,true,1),
('grammar','multiple_choice','The mechanic reported that the brake pads _____ worn beyond limits.\nA) is\nB) was\nC) were\nD) are','C','B1','medium','tense_usage','landing_gear','maintenance',true,true,1),
('grammar','multiple_choice','Please ensure that all tools _____ returned to the toolbox after use.\nA) is\nB) are\nC) was\nD) has been','B','A2','easy','passive_voice','general','maintenance',true,true,1),
('grammar','multiple_choice','The aircraft _____ in the hangar since yesterday morning.\nA) is\nB) was\nC) has been\nD) had','C','B1','medium','tense_usage','general','maintenance',true,true,1),
('grammar','multiple_choice','A torque wrench is used _____ tightening bolts to a specific value.\nA) to\nB) for\nC) with\nD) by','B','A2','easy','phraseology_grammar','general','maintenance',true,true,1),
('grammar','fill_blank','Complete: The corrosion must be treated _____ (immediate) to prevent further damage.','immediately','B1','medium','structural_accuracy','airframe','maintenance',true,true,1),
('grammar','multiple_choice','The work order states that the component _____ be replaced within 48 hours.\nA) shall\nB) will\nC) can\nD) may','A','B1','medium','phraseology_grammar','general','maintenance',true,true,1),
('grammar','multiple_choice','After _____ the inspection, the engineer signed the release certificate.\nA) complete\nB) completing\nC) completed\nD) to complete','B','B1','medium','structural_accuracy','general','maintenance',true,true,1),
('grammar','multiple_choice','The safety wire _____ correctly installed on the drain plug.\nA) is not\nB) does not\nC) not\nD) no','A','A2','easy','passive_voice','general','maintenance',true,true,1),
('grammar','fill_blank','Complete: The borescope inspection was performed _____ (careful) on all turbine blades.','carefully','A2','easy','structural_accuracy','engine','maintenance',true,true,1),
('grammar','multiple_choice','The corrosion was found _____ the leading edge of the wing.\nA) in\nB) on\nC) at\nD) by','B','A2','easy','phraseology_grammar','airframe','maintenance',true,true,1),
('grammar','multiple_choice','The technician asked his supervisor _____ he should use a different sealant.\nA) what\nB) which\nC) whether\nD) how','C','B1','medium','structural_accuracy','general','maintenance',true,true,1),
('grammar','multiple_choice','We _____ replace the gasket before the engine can be tested.\nA) need to\nB) need\nC) needs to\nD) needing','A','A2','easy','structural_accuracy','engine','maintenance',true,true,1),
('grammar','multiple_choice','The NDT results showed that the crack _____ propagated further than expected.\nA) has\nB) had\nC) have\nD) having','B','B2','hard','tense_usage','airframe','maintenance',true,true,1),
('grammar','multiple_choice','_____ the repair is completed, a functional test must be performed.\nA) Once\nB) While\nC) During\nD) Since','A','B1','medium','structural_accuracy','general','maintenance',true,true,1),
('grammar','fill_blank','Complete: The hydraulic fluid level was _____ (danger) low.','dangerously','B1','medium','structural_accuracy','hydraulic','maintenance',true,true,1),
('grammar','multiple_choice','Each component _____ have a valid serviceable tag before installation.\nA) must\nB) can\nC) might\nD) could','A','B1','medium','phraseology_grammar','general','maintenance',true,true,1),

-- Reading (10)
('reading','multiple_choice','Read the maintenance instruction:\n\n"CAUTION: Before removing the fuel filter, ensure the fuel supply valve is in the CLOSED position. Failure to close the valve may result in fuel spillage and fire hazard. Use only approved containers for residual fuel."\n\nWhat must be done FIRST?\nA) Collect residual fuel\nB) Close the fuel supply valve\nC) Check for fire hazards\nD) Open the filter housing','B','A2','easy','technical_manual','fuel_system','maintenance',true,true,1),
('reading','multiple_choice','Read the work order:\n\n"Task: Replace left main gear tire. Ref: AMM 32-45-11. Priority: Routine. Tire pressure at 145 psi (min: 150 psi). New tire P/N: GY-2847-3. Torque: 300 in-lbs per AMM."\n\nWhy must the tire be replaced?\nA) Flight hour limit reached\nB) Pressure below minimum\nC) Tread too shallow\nD) Wheel bolts damaged','B','B1','medium','sop_comprehension','landing_gear','maintenance',true,true,1),
('reading','multiple_choice','Read the safety notice:\n\n"All personnel in fuel tank areas must wear anti-static clothing and use non-sparking tools. Mobile phones prohibited within 15m of open fuel tanks. Violations: immediate removal from work area."\n\nWhat is NOT allowed near fuel tanks?\nA) Anti-static clothing\nB) Non-sparking tools\nC) Mobile phones\nD) Safety goggles','C','A2','easy','safety_card_reading','fuel_system','maintenance',true,true,1),
('reading','multiple_choice','Read the AMM excerpt:\n\n"5.2 Lubrication: The nose gear steering mechanism shall be lubricated with MIL-G-81322 grease at intervals not exceeding 200 FH or 90 calendar days, whichever first. Apply through upper torque link fitting until fresh grease at lower seal."\n\nHow often must the nose gear be lubricated?\nA) Every 200 flights\nB) Every 200 FH or 90 days, whichever first\nC) Every 90 flights\nD) Only when grease appears','B','B1','medium','technical_manual','landing_gear','maintenance',true,true,1),
('reading','multiple_choice','Read the SRM (Structural Repair Manual) entry:\n\n"Allowable damage: Dents in fuselage skin not exceeding 0.5mm depth and 30mm diameter. Dents deeper than 0.5mm or within 25mm of a rivet line require engineering assessment. Scratches deeper than 0.1mm must be blended and treated with corrosion inhibitor."\n\nA dent is 0.8mm deep. What should be done?\nA) No action needed\nB) Engineering assessment required\nC) Apply corrosion inhibitor\nD) Blend the dent','B','B2','hard','technical_manual','airframe','maintenance',true,true,1),
('reading','multiple_choice','Read the tool calibration notice:\n\n"All torque wrenches used on critical flight-safety components must be calibrated every 6 months or after 5000 cycles of use, whichever occurs first. Out-of-calibration tools must not be used and should be tagged with a red UNSERVICEABLE label."\n\nWhat happens to out-of-calibration tools?\nA) They can still be used with caution\nB) They are tagged red and cannot be used\nC) They are discarded\nD) They are sent to the manufacturer','B','B1','medium','sop_comprehension','general','maintenance',true,true,1),
('reading','multiple_choice','Read the service bulletin:\n\n"SB-A320-57-1089: Inspect wing root fairing attachment bolts for corrosion. Applicability: All A320 aircraft with MSN below 5000. Compliance: Within next 2000 FH or 12 months. Action: Replace any bolt with visible corrosion, apply new sealant per AMM 51-70-11."\n\nWhich aircraft are affected?\nA) All A320s\nB) A320s with MSN below 5000\nC) Only new A320s\nD) A320neo only','B','B2','hard','technical_manual','airframe','maintenance',true,true,1),
('reading','multiple_choice','Read the shift log:\n\n"Night shift summary: TC-SUN — C-check Day 3, engine 1 borescope complete (no findings), landing gear overhaul in progress. TC-AIR — tire change completed Bay 5, awaiting QC inspection. TC-FLY — AOG, waiting for hydraulic pump (ETA tomorrow 0800)."\n\nWhich aircraft is AOG?\nA) TC-SUN\nB) TC-AIR\nC) TC-FLY\nD) All of them','C','B1','medium','sop_comprehension','general','maintenance',true,true,1),
('reading','multiple_choice','Read the hazardous materials guide:\n\n"SKYDROL hydraulic fluid: AVOID skin and eye contact. Wear nitrile gloves and safety goggles. If skin contact occurs, wash immediately with soap and water for 15 minutes. If swallowed, do NOT induce vomiting — seek medical attention immediately."\n\nWhat type of gloves should be worn?\nA) Latex gloves\nB) Nitrile gloves\nC) Cotton gloves\nD) No gloves needed','B','A2','easy','safety_card_reading','hydraulic','maintenance',true,true,1),
('reading','multiple_choice','Read the AD (Airworthiness Directive):\n\n"AD 2026-05-12: Mandatory inspection of fuel quantity indicating system wiring harness for chafing. Affected: B737-800 with line numbers 3500-4200. Compliance: Within 500 FH of effective date. Failure to comply results in aircraft grounding."\n\nWhat is the consequence of non-compliance?\nA) A warning letter\nB) The aircraft must be grounded\nC) A fine\nD) No consequence','B','B2','hard','technical_manual','fuel_system','maintenance',true,true,1),

-- Writing (8)
('writing','written_response','During a routine inspection of a B737, you found a 3cm crack on the left wing leading edge near the fuel vent. Write a maintenance log entry (at least 50 words) describing what you found, location, and recommended action.','Model answer should include aircraft type/reg, specific location, crack dimensions, findings, recommendation for NDT inspection and engineering assessment.','B1','medium','maintenance_log','airframe','maintenance',true,true,1),
('writing','written_response','You found tools left inside an engine cowling after maintenance — a serious FOD risk. Write an incident report (at least 50 words) describing what happened, where, and what you did.','Model answer should include factual description, tool details, location, removal, reporting to supervisor, tool inventory check.','A2','easy','incident_report','engine','maintenance',true,true,1),
('writing','written_response','Write an email to the parts department (at least 50 words) urgently requesting a replacement hydraulic actuator for an AOG aircraft. Include the aircraft registration, part number, and delivery urgency.','Model answer should include formal request, aircraft details, part specifics, AOG status, requested delivery time.','B1','medium','operational_message','hydraulic','maintenance',true,true,1),
('writing','written_response','A new apprentice joined your team. Write an email to your supervisor (at least 50 words) about the apprentice, planned tasks for the week, and pending safety training.','Model answer should include apprentice details, task assignments, training requirements, supervision plan.','B1','medium','operational_message','general','maintenance',true,true,1),
('writing','written_response','Write a defect report (at least 60 words) for an intermittent autopilot disconnect that occurred 3 times during the last 10 flights. Include the system affected, frequency, and your troubleshooting recommendation.','Model answer should include system ID, frequency of occurrence, flight conditions, possible causes, recommended troubleshooting steps.','B2','hard','technical_description','general','maintenance',true,true,1),
('writing','written_response','You completed an engine oil change and subsequent ground run. Write the technical log entry (at least 50 words) including oil type, quantity, and test results.','Model answer should include engine position, oil spec, quantity added, ground run parameters, results satisfactory.','B1','medium','maintenance_log','engine','maintenance',true,true,1),
('writing','written_response','Write a safety observation report (at least 50 words) about inadequate lighting in the wheel bay area that makes inspection difficult and potentially dangerous during night shifts.','Model answer should include specific location, safety concern, impact on inspection quality, recommendation for additional lighting.','A2','easy','safety_report','general','maintenance',true,true,1),
('writing','written_response','Write a brief procedure description (at least 60 words) explaining how to perform a brake wear pin check on a main landing gear wheel. Include safety precautions.','Model answer should include chocking aircraft, safety procedures, visual inspection method, wear limits, documentation.','B2','medium','technical_description','landing_gear','maintenance',true,true,1),

-- Speaking (8)
('speaking','audio_response','Describe the steps for a daily pre-flight visual inspection. Talk about at least 3 areas and why each is important.\n\nSpeak for at least 30 seconds.','Expected: Airframe check, tires, fluids, control surfaces, leaks, fasteners. Clear structure.','B1','medium','oral_briefing','general','maintenance',true,true,1),
('speaking','audio_response','Your supervisor asks: "What safety precautions do you take near fuel systems?" Respond with at least 3 precautions.\n\nSpeak for at least 30 seconds.','Expected: Anti-static clothing, non-sparking tools, no electronics, fire extinguisher, ventilation.','A2','easy','ground_communication','fuel_system','maintenance',true,true,1),
('speaking','audio_response','Roleplay: Call the parts department to order a replacement brake assembly for an A320. Explain what you need, why, and ask about availability.\n\nSpeak for at least 30 seconds.','Expected: Self-identification, aircraft details, part needed, reason, delivery question.','B1','medium','ground_communication','landing_gear','maintenance',true,true,1),
('speaking','audio_response','Explain what FOD means and why it is dangerous in aviation. Give one prevention example.\n\nSpeak for at least 30 seconds.','Expected: FOD definition, examples of damage, prevention measures (tool control, clean areas, FOD walks).','A2','easy','oral_briefing','general','maintenance',true,true,1),
('speaking','audio_response','You are handing over to the night shift. Brief them on: what you completed today, what is pending, and any safety concerns.\n\nSpeak for at least 45 seconds.','Expected: Structured handover, completed tasks, pending work, parts status, safety notes, AOG status.','B1','medium','crew_coordination','general','maintenance',true,true,1),
('speaking','audio_response','Describe the process of performing a borescope inspection on a turbine engine. What are you looking for?\n\nSpeak for at least 40 seconds.','Expected: Equipment setup, inspection areas, common findings (cracks, erosion, FOD damage), documentation.','B2','hard','technical_description','engine','maintenance',true,true,1),
('speaking','audio_response','Roleplay: A pilot calls you on the intercom reporting a strange vibration during engine start. Ask diagnostic questions and explain what you will check.\n\nSpeak for at least 40 seconds.','Expected: Clarifying questions, systematic approach, possible causes, inspection plan.','B2','medium','ground_communication','engine','maintenance',true,true,1),
('speaking','audio_response','Explain to a new team member the importance of the "Duplicate Inspection" procedure. When is it required and why?\n\nSpeak for at least 30 seconds.','Expected: Definition, when required (flight controls, engines), two-person verification, safety purpose.','B1','medium','oral_briefing','general','maintenance',true,true,1),

-- Listening (12)
('listening','multiple_choice','[AUDIO] "Maintenance Control, this is Hangar 3. We have completed the engine oil change on TC-FLY. Oil quantity 12 quarts. Ready for engine run-up test."\n\nWhat was completed?\nA) Tire change\nB) Engine oil change\nC) Fuel system check\nD) Hydraulic test','B','A2','easy','ground_ops_radio','engine','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "Attention all personnel. Thunderstorm warning — all outdoor maintenance suspended immediately. Secure aircraft on ramp with additional tie-downs. Move to indoor locations. Resume after all-clear."\n\nWhat must happen to ramp aircraft?\nA) Move to hangar\nB) Secure with extra tie-downs\nC) Fuel immediately\nD) Nothing','B','A2','easy','emergency_broadcast','general','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "Night shift status: TC-SUN Bay 2 needs left main gear tire — parts staged. TC-AIR Bay 5 waiting for hydraulic pump from stores, ETA midnight. TC-FLY in paint shop — not our responsibility tonight."\n\nWhich aircraft awaits a stores part?\nA) TC-SUN\nB) TC-AIR\nC) TC-FLY\nD) All of them','B','B1','medium','cockpit_communication','general','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "Ground, Maintenance Tug 7. Requesting tow permission — TC-JET from Gate 14 to Hangar 2 via Taxiway Alpha. Wing walkers in position."\n\nWhere is the aircraft going?\nA) Gate 14\nB) Hangar 2\nC) Taxiway Alpha\nD) The runway','B','A2','easy','ground_ops_radio','general','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "Team, we have an AOG on TC-BIRD. Right engine starter motor failed. Airline needs it by 0600 tomorrow. I need two experienced techs on this immediately."\n\nWhat does AOG mean here?\nA) Aircraft On Ground — cannot fly until repaired\nB) Aircraft Operating Good\nC) Arrival On Gate\nD) All Operations Go','A','B1','medium','cockpit_communication','engine','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "The replacement hydraulic actuator for TC-SUN arrived from Istanbul. P/N HYD-4421-B. Currently in Receiving — needs Quality inspection before install. ETA release: 1400 local."\n\nWhen will the part be available?\nA) Immediately\nB) After quality inspection, around 1400\nC) Tomorrow morning\nD) It hasn''t arrived','B','B1','medium','ground_ops_radio','hydraulic','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "When you lock-wire a bolt, ensure the wire pulls in the tightening direction. Use 0.032-inch wire for standard applications. Minimum 6 twists per inch. Never reuse lock wire."\n\nMinimum twists per inch?\nA) 3\nB) 4\nC) 6\nD) 8','C','B1','medium','ground_ops_radio','general','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "Calibration lab closed this Friday for upgrades. All torque wrenches due this week must be submitted by Thursday end of shift. Late submissions scheduled next week."\n\nDeadline for calibration submissions?\nA) Friday morning\nB) Thursday end of shift\nC) Next Monday\nD) Immediately','B','A2','easy','ground_ops_radio','general','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "Warning: The aircraft at Stand 9 still has live electrical power connected. Do NOT disconnect the external power unit until the avionics team completes their software update. Estimated completion: 45 minutes."\n\nWhat must NOT be done?\nA) Board the aircraft\nB) Disconnect external power\nC) Start the engines\nD) Open the cargo doors','B','B1','medium','ground_ops_radio','general','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "Quality inspector to Hangar 4: I have completed the buy-back inspection on the left engine following the compressor blade replacement. All torque values confirmed. Documentation is in order. The engine is released to service. You may proceed with cowl closure."\n\nWhat can the team do now?\nA) Replace another blade\nB) Close the engine cowlings\nC) Wait for another inspection\nD) Order more parts','B','B1','medium','ground_ops_radio','engine','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "Attention maintenance: runway FOD check commencing in 10 minutes. All personnel and vehicles must vacate Runway 36L and associated taxiways Alpha and Bravo. Confirm when your area is clear on this frequency."\n\nWhat is about to happen?\nA) Aircraft landing\nB) Runway FOD inspection\nC) Fire drill\nD) Runway painting','B','A2','easy','ground_ops_radio','general','maintenance',true,true,1),
('listening','multiple_choice','[AUDIO] "The NDT technician reports that the ultrasonic inspection of the wing spar at Station 245 shows an indication of 4mm — this exceeds the allowable limit of 2.5mm per SRM. Engineering has been notified. Do not reassemble until disposition received."\n\nWhat must happen before reassembly?\nA) Another NDT test\nB) Engineering disposition must be received\nC) The spar must be replaced\nD) Nothing — it is acceptable','B','B2','hard','ground_ops_radio','airframe','maintenance',true,true,1);


